import "./Footer.css";

/**
 * Footer
 * Minimal brand strip with Indian & Tamil Nadu wedding photos.
 */
export default function Footer() {
  const year = new Date().getFullYear();

  const footerPhotos = [
    {
      src: "https://images.unsplash.com/photo-1519741497674-611481863552?w=300&q=85&fm=jpg",
      alt: "Indian Bridal Portrait",
    },
    {
      src: "https://images.unsplash.com/photo-1583939003579-730e3918a45a?w=300&q=85&fm=jpg",
      alt: "Tamil Nadu Temple Wedding",
    },
    {
      src: "https://images.unsplash.com/photo-1629968033108-f1cd3a31b63b?w=300&q=85&fm=jpg",
      alt: "Indian Wedding Ceremony",
    },
    {
      src: "https://images.unsplash.com/photo-1516661904166-bac77fcdc2c8?w=300&q=85&fm=jpg",
      alt: "South Indian Wedding",
    },
    {
      src: "https://images.unsplash.com/photo-1591604021695-0c69b7c05981?w=300&q=85&fm=jpg",
      alt: "Traditional Indian Celebration",
    },
    {
      src: "https://images.unsplash.com/photo-1511285560929-80b456fea0bc?w=300&q=85&fm=jpg",
      alt: "Tamil Brahmin Wedding",
    },
  ];

  return (
    <footer className="footer">
      <div className="footer__content">
        <div className="footer__text">
          <span className="footer__brand">
            Ayyan Studio <em>Classics</em>
          </span>
          <span className="footer__info">
            © {year} · South Indian Wedding Specialists
          </span>
        </div>

        <div className="footer__gallery">
          {footerPhotos.map((photo, idx) => (
            <div key={idx} className="footer__gallery-item">
              <img src={photo.src} alt={photo.alt} loading="lazy" />
            </div>
          ))}
        </div>
      </div>
    </footer>
  );
}
